    private List getAzureLinks(String identityName) {

    import sailpoint.api.IdentityService;
    import sailpoint.object.Identity;
    import sailpoint.object.Link;
    
    Application azureApp = context.getObjectByName(Application.class, "Azure");

    Identity refIdentity = context.getObjectByName(Identity.class, identityName);

    IdentityService iService = new IdentityService(context);

    List azureLinks = iService.getLinks(refIdentity, azureApp);

    return azureLinks;

  }


  private String getAzureAuthToken() {



    Application azureApp = context.getObjectByName(Application.class, "Azure");


    private String domainName = azureApp.getAttributeValue("domainName").toString();
    private String tokenEndpoint = "https://login.microsoftonline.com/"+domainName+"/oauth2/v2.0/token";
    private String grantType = "client_credentials";
    private String clientID = azureApp.getAttributeValue("clientID").toString();
    private String clientSecret = context.decrypt(azureApp.getAttributeValue("clientSecret").toString());
    private String scope = "https://graph.microsoft.com/.default";



    /* HTTPCLIENT AND HTTPPOST OBJECT */

    HttpClient httpClient = HttpClientBuilder.create().build();

    HttpPost httpPost = new HttpPost(tokenEndpoint);



    /* AUTHENTICATION CREDENTIALS ENCODING */

    String base64Credentials = Base64.getEncoder().encodeToString((clientID + ":" + clientSecret).getBytes());



    /* HEADER INFO */

    httpPost.addHeader("Authorization", "Basic " + base64Credentials);

    httpPost.addHeader("Content-Type", "application/x-www-form-urlencoded");



    /* OAUTH PARAMETERS ADDED TO BODY */

    StringEntity input = null;

    try {

      input = new StringEntity("grant_type=" + grantType + "&scope=" + scope);

      httpPost.setEntity(input);

    } catch (UnsupportedEncodingException e) {

      e.printStackTrace();

    }



    /* SEND AND RETRIEVE RESPONSE */

    HttpResponse response = null;

    try {

      response = httpClient.execute(httpPost);

    } catch (IOException e) {

      e.printStackTrace();

    }



    /* RESPONSE AS STRING */

    String result = null;

    try {

      result = IOUtils.toString(response.getEntity().getContent(), "UTF-8");

      JSONParser parser = new JSONParser();
      JSONObject jsonOutput = (JSONObject) parser.parse(result);
      return jsonOutput.get("access_token");


    } catch (IOException e) {

      e.printStackTrace();
      return result;

    }

  }

  private String getAzureLinkUpn(String identityName) {

    import sailpoint.api.IdentityService;
    import sailpoint.object.Identity;
    import sailpoint.object.Link;
    import sailpoint.object.Application;

    IdentityService idService = new IdentityService(context);  

    Identity refIdentity = context.getObjectByName(Identity.class, identityName);



    List links = refIdentity.getLinks();

    for(Link appLink:links) {
      if(appLink.getApplication().getName().equalsIgnoreCase("Azure")){
        String upn = appLink.getAttribute("userPrincipalName");

        System.out.println(upn);
        return upn;
      }

    }

    return null;
  }



