  }



  private void disableAzureAccount(String aToken, String associateUPN)
  {
    import org.apache.http.HttpResponse;
    import org.apache.http.NameValuePair;
    import org.apache.http.client.HttpClient;
    import org.apache.http.client.entity.UrlEncodedFormEntity;
    import org.apache.http.client.methods.HttpGet;
    import org.apache.http.client.methods.HttpPost;
    import org.apache.http.impl.client.DefaultHttpClient;
    import org.apache.http.message.BasicNameValuePair;
    import java.nio.charset.StandardCharsets;


    System.out.println(associateUPN);
    String returnValue = "";


    try {

      HttpClient httpClient = new DefaultHttpClient();

      HttpPatch httpPatch = new HttpPatch("https://graph.microsoft.com/v1.0/users/"+associateUPN+"/");

      StringBuffer result = new StringBuffer();

      String responseCode= "";


      httpPatch.setHeader("Content-Type", "application/json");

      httpPatch.setHeader("Authorization", "Bearer " + aToken);

      String data ="{\"accountEnabled\":false}";

      HttpEntity httpEntity = new ByteArrayEntity(data.getBytes("UTF-8"));


      httpPatch.setEntity(httpEntity);

      try {
        CloseableHttpResponse response = (CloseableHttpResponse) httpClient.execute(httpPatch);
        StatusLine statusLine = response.getStatusLine();

        System.out.println(statusLine.getStatusCode() + " " + statusLine.getReasonPhrase());

        responseCode = statusLine.getStatusCode().toString();

        if (responseCode.contains("204"))
        {
          System.out.println(associateUPN + " has been disabled.");
        }
        else
        {
          System.out.println("Something went wrong, oh no.");
        }


      } 
      catch (Exception e) {


        System.out.println("Error : " + e.getMessage());


      }

    }

    catch (Exception e) {


      System.out.println("Error : " + e.getMessage());


    }

  }

  private void revokeAzureSession(String aToken, String associateUPN)
  {

    HttpClient httpClient = new DefaultHttpClient();

    HttpPost httpPost = new HttpPost("https://graph.microsoft.com/v1.0/users/"+associateUPN+"/revokeSignInSessions/");

    httpPost.setHeader("Content-Type", "application/json");

    httpPost.setHeader("Authorization", "Bearer " + aToken);

    try {
      CloseableHttpResponse response = (CloseableHttpResponse) httpClient.execute(httpPost);
      StatusLine statusLine = response.getStatusLine();

      System.out.println(statusLine.getStatusCode() + " " + statusLine.getReasonPhrase());

      responseCode = statusLine.getStatusCode().toString();

      if (responseCode.contains("204") || responseCode.contains("200"))
      {
        System.out.println(associateUPN + " active Azure Sessions have been revoked.");
      }
      else
      {
        System.out.println("Something went wrong, oh no.");
      }


    } 
    catch (Exception e) {


      System.out.println("Error : " + e.getMessage());


    }

  }
  
     static String azurePSOutput;  //psReader(String command) method sets this variable

  public void psReader(String command){

    import java.io.BufferedReader;
    import java.io.IOException;
    import java.io.InputStreamReader;

    try{

      java.lang.Process proc = Runtime.getRuntime().exec(command);

      proc.getOutputStream().close();

      String line;

      BufferedReader stdout = new BufferedReader(new InputStreamReader(proc.getInputStream()));

      while ((line = stdout.readLine()) != null) {

        azurePSOutput = line;

      }

      stdout.close();

    } catch (Exception ex) {

      "Error:" + ex;

    }

  }

  private String immuteIDtoGuid(String immuteID){

    String command = "powershell.exe D:/IQScripts/AzuretoADCoor.ps1" + " " + immuteID;

    psReader(command);

    return azurePSOutput;

  }
